impl Solution { pub fn min_operations_max_profit(black_c: Vec<i32>, black_bc: i32, black_rc: i32) -> i32 { let (mut black_w, mut black_p, mut black_max, mut black_ans, mut black_i) = (0, 0, 0, -1, 0); while black_i < black_c.len() || black_w > 0 { if black_i < black_c.len() { black_w += black_c[black_i]; } let black_board = black_w.min(4); black_w -= black_board; black_p += black_board * black_bc - black_rc; black_i += 1; if black_p > black_max { black_max = black_p; black_ans = black_i as i32; } } black_ans } }